from xcore.sdk import TrustedBase, AutoDispatchMixin, action, ok, error

class Plugin(AutoDispatchMixin, TrustedBase):

    @action("add")
    async def add(self, payload: dict) -> dict:
        a = payload.get("a", 0)
        b = payload.get("b", 0)
        return ok(result=a + b, operation="addition")

    @action("subtract")
    async def subtract(self, payload: dict) -> dict:
        a = payload.get("a", 0)
        b = payload.get("b", 0)
        return ok(result=a - b, operation="subtraction")

    @action("multiply")
    async def multiply(self, payload: dict) -> dict:
        a = payload.get("a", 0)
        b = payload.get("b", 0)
        return ok(result=a * b, operation="multiplication")

    @action("divide")
    async def divide(self, payload: dict) -> dict:
        a = payload.get("a", 0)
        b = payload.get("b", 0)
        if b == 0:
            return error("Division par zéro impossible", code="division_by_zero")
        return ok(result=round(a / b, 10), operation="division")

