from pydantic import BaseModel
from sqlalchemy import Column, Integer, String, Boolean
from sqlalchemy.orm import declarative_base
from xcore.sdk import (
    TrustedBase, AutoDispatchMixin, RoutedPlugin,
    BaseAsyncRepository, action, route, validate_payload, ok, error
)

Base = declarative_base()

class User(Base):
    __tablename__ = "users"
    id = Column(Integer, primary_key=True)
    name = Column(String, nullable=False)
    email = Column(String, nullable=False, unique=True)
    active = Column(Boolean, default=True)

class CreateUser(BaseModel):
    name: str
    email: str

class UserRepository(BaseAsyncRepository[User]):
    pass

class Plugin(RoutedPlugin, AutoDispatchMixin, TrustedBase):

    async def on_load(self) -> None:
        self.db = self.get_service("db")
        self.cache = self.get_service("cache")
        self.repo = UserRepository(User)

    @action("get_user")
    async def get_user_ipc(self, payload: dict) -> dict:
        user_id = payload.get("id")
        if not user_id:
            return error("Le champ 'id' est obligatoire", code="missing_field")
        async with self.db.session() as session:
            user = await self.repo.get_by_id(session, user_id)
            if not user:
                return error("Utilisateur non trouvé", code="not_found")
            return ok(id=user.id, name=user.name, email=user.email, active=user.active)

    @action("create_user")
    @validate_payload(CreateUser, type_response="dict")
    async def create_user_ipc(self, data: dict) -> dict:
        async with self.db.session() as session:
            user = User(name=data["name"], email=data["email"])
            created = await self.repo.create(session, user)
            await self.cache.delete("users:list")
            return ok(id=created.id, name=created.name, email=created.email)

    @action("delete_user")
    async def delete_user_ipc(self, payload: dict) -> dict:
        user_id = payload.get("id")
        if not user_id:
            return error("Le champ 'id' est obligatoire", code="missing_field")
        async with self.db.session() as session:
            deleted = await self.repo.delete(session, user_id)
            if not deleted:
                return error("Utilisateur non trouvé", code="not_found")
            await self.cache.delete("users:list")
            return ok(deleted=True)

    @route("/", method="GET")
    async def list_users(self):
        cached = await self.cache.get("users:list")
        if cached:
            return {"users": cached, "cached": True}
        async with self.db.session() as session:
            users = await self.repo.get_all(session)
            result = [{"id": u.id, "name": u.name, "email": u.email, "active": u.active} for u in users]
            await self.cache.set("users:list", result, ttl=120)
            return {"users": result, "cached": False}

    @route("/{user_id}", method="GET")
    async def get_user(self, user_id: int):
        async with self.db.session() as session:
            user = await self.repo.get_by_id(session, user_id)
            if not user:
                return error("Utilisateur non trouvé", code="not_found")
            return {"id": user.id, "name": user.name, "email": user.email, "active": user.active}

    @route("/{user_id}", method="DELETE", status_code=204)
    async def delete_user_http(self, user_id: int):
        async with self.db.session() as session:
            deleted = await self.repo.delete(session, user_id)
            if not deleted:
                return error("Utilisateur non trouvé", code="not_found")
            await self.cache.delete("users:list")
            return None

