import httpx
from xcore.sdk import TrustedBase, AutoDispatchMixin, action, ok, error

API_BASE = "https://wttr.in"

class Plugin(AutoDispatchMixin, TrustedBase):

    @action("get_weather")
    async def get_weather(self, payload: dict) -> dict:
        city = payload.get("city")
        if not city:
            return error("Le champ 'city' est obligatoire", code="missing_field")
        try:
            async with httpx.AsyncClient(timeout=8) as client:
                response = await client.get(f"{API_BASE}/{city}?format=j1")
                if response.status_code == 404:
                    return error("Ville non trouvée", code="not_found")
                if response.status_code != 200:
                    return error("Erreur API météo", code="api_error")
                data = response.json()
                current = data.get("current_condition", [{}])[0]
                return ok(
                    city=city,
                    temp_c=current.get("temp_C"),
                    feels_like_c=current.get("FeelsLikeC"),
                    humidity=current.get("humidity"),
                    description=current.get("weatherDesc", [{}])[0].get("value", "")
                )
        except httpx.TimeoutException:
            return error("Timeout lors de la récupération météo", code="timeout")
        except Exception as e:
            return error(f"Erreur inattendue: {e}", code="internal_error")

    @action("get_forecast")
    async def get_forecast(self, payload: dict) -> dict:
        city = payload.get("city")
        if not city:
            return error("Le champ 'city' est obligatoire", code="missing_field")
        try:
            async with httpx.AsyncClient(timeout=8) as client:
                response = await client.get(f"{API_BASE}/{city}?format=j1")
                if response.status_code != 200:
                    return error("Ville non trouvée", code="not_found")
                data = response.json()
                forecast = data.get("weather", [])
                days = [{"date": d.get("date"), "max_c": d.get("maxtempC"), "min_c": d.get("mintempC")} for d in forecast]
                return ok(city=city, forecast=days)
        except httpx.TimeoutException:
            return error("Timeout", code="timeout")
        except Exception as e:
            return error(f"Erreur inattendue: {e}", code="internal_error")

