import re
from xcore.sdk import TrustedBase, AutoDispatchMixin, action, ok, error

ACCENTS_MAP = [
    (r"[àáâãäå]", "a"), (r"[èéêë]", "e"), (r"[ìíîï]", "i"),
    (r"[òóôõö]", "o"), (r"[ùúûü]", "u"), (r"[ç]", "c"),
    (r"[ñ]", "n"),
]

class Plugin(AutoDispatchMixin, TrustedBase):

    @action("uppercase")
    async def uppercase(self, payload: dict) -> dict:
        text = payload.get("text", "")
        return ok(result=text.upper(), length=len(text))

    @action("lowercase")
    async def lowercase(self, payload: dict) -> dict:
        text = payload.get("text", "")
        return ok(result=text.lower(), length=len(text))

    @action("slugify")
    async def slugify(self, payload: dict) -> dict:
        text = payload.get("text", "")
        slug = text.lower().strip()
        for pattern, replacement in ACCENTS_MAP:
            slug = re.sub(pattern, replacement, slug)
        slug = re.sub(r"[^a-z0-9\s-]", "", slug)
        slug = re.sub(r"[\s-]+", "-", slug).strip("-")
        return ok(result=slug, original=text)

    @action("truncate")
    async def truncate(self, payload: dict) -> dict:
        text = payload.get("text", "")
        max_length = payload.get("max_length", 100)
        suffix = payload.get("suffix", "...")
        if not isinstance(max_length, int) or max_length <= 0:
            return error("max_length doit être un entier positif", code="invalid_param")
        if len(text) <= max_length:
            return ok(result=text, truncated=False)
        return ok(result=text[:max_length].rstrip() + suffix, truncated=True)

    @action("word_count")
    async def word_count(self, payload: dict) -> dict:
        text = payload.get("text", "")
        words = len(text.split()) if text.strip() else 0
        return ok(
            words=words,
            characters=len(text),
            characters_no_spaces=len(text.replace(" ", ""))
        )

    @action("capitalize")
    async def capitalize(self, payload: dict) -> dict:
        text = payload.get("text", "")
        return ok(result=text.capitalize())

    @action("title_case")
    async def title_case(self, payload: dict) -> dict:
        text = payload.get("text", "")
        return ok(result=text.title())

