import hashlib
import random
import string
import uuid
from datetime import datetime, timezone
from xcore.sdk import TrustedBase, AutoDispatchMixin, action, ok, error

_NANOID_ALPHABET = string.ascii_letters + string.digits + "-_"

class Plugin(AutoDispatchMixin, TrustedBase):

    @action("uuid4")
    async def generate_uuid4(self, payload: dict) -> dict:
        count = min(int(payload.get("count", 1)), 100)
        ids = [str(uuid.uuid4()) for _ in range(count)]
        return ok(ids=ids, count=count, version="v4")

    @action("uuid5")
    async def generate_uuid5(self, payload: dict) -> dict:
        name = payload.get("name")
        namespace_str = payload.get("namespace", "url")
        if not name:
            return error("Le champ 'name' est obligatoire", code="missing_field")
        namespaces = {
            "url": uuid.NAMESPACE_URL,
            "dns": uuid.NAMESPACE_DNS,
            "oid": uuid.NAMESPACE_OID,
        }
        ns = namespaces.get(namespace_str, uuid.NAMESPACE_URL)
        generated = str(uuid.uuid5(ns, name))
        return ok(id=generated, name=name, namespace=namespace_str, version="v5", deterministic=True)

    @action("nanoid")
    async def generate_nanoid(self, payload: dict) -> dict:
        size = max(8, min(int(payload.get("size", 21)), 128))
        count = min(int(payload.get("count", 1)), 100)
        ids = ["".join(random.choices(_NANOID_ALPHABET, k=size)) for _ in range(count)]
        return ok(ids=ids, size=size, count=count)

    @action("timestamp_id")
    async def generate_timestamp_id(self, payload: dict) -> dict:
        prefix = payload.get("prefix", "")
        suffix_len = max(4, min(int(payload.get("suffix_len", 8)), 32))
        ts = datetime.now(timezone.utc).strftime("%Y%m%d%H%M%S%f")
        suffix = "".join(random.choices(string.ascii_lowercase + string.digits, k=suffix_len))
        sep = payload.get("sep", "_")
        parts = [p for p in [prefix, ts, suffix] if p]
        generated = sep.join(parts)
        return ok(id=generated, timestamp=ts, prefix=prefix)

    @action("hash_id")
    async def generate_hash_id(self, payload: dict) -> dict:
        value = payload.get("value")
        algorithm = payload.get("algorithm", "sha256")
        if not value:
            return error("Le champ 'value' est obligatoire", code="missing_field")
        if algorithm not in ("sha256", "sha1", "md5"):
            return error("Algorithm invalide. Valeurs: sha256, sha1, md5", code="invalid_param")
        h = hashlib.new(algorithm, str(value).encode()).hexdigest()
        length = payload.get("length")
        if length:
            h = h[:int(length)]
        return ok(id=h, algorithm=algorithm, original=str(value))

