from datetime import datetime, timedelta, timezone
from xcore.sdk import TrustedBase, AutoDispatchMixin, action, ok, error

FORMATS = {
    "iso": "%Y-%m-%dT%H:%M:%S",
    "date": "%Y-%m-%d",
    "datetime_fr": "%d/%m/%Y %H:%M",
    "date_fr": "%d/%m/%Y",
    "rfc2822": "%a, %d %b %Y %H:%M:%S +0000",
}

class Plugin(AutoDispatchMixin, TrustedBase):

    @action("now")
    async def now(self, payload: dict) -> dict:
        fmt = payload.get("format", "iso")
        tz_offset = payload.get("tz_offset", 0)
        tz = timezone(timedelta(hours=tz_offset))
        now = datetime.now(tz)
        pattern = FORMATS.get(fmt, FORMATS["iso"])
        return ok(
            iso=now.isoformat(),
            formatted=now.strftime(pattern),
            timestamp=int(now.timestamp()),
            format=fmt
        )

    @action("format")
    async def format_date(self, payload: dict) -> dict:
        date_str = payload.get("date")
        from_fmt = payload.get("from_format", "iso")
        to_fmt = payload.get("to_format", "date_fr")
        if not date_str:
            return error("Le champ 'date' est obligatoire", code="missing_field")
        try:
            pattern_from = FORMATS.get(from_fmt, from_fmt)
            dt = datetime.strptime(date_str, pattern_from)
            pattern_to = FORMATS.get(to_fmt, to_fmt)
            return ok(input=date_str, output=dt.strftime(pattern_to), from_format=from_fmt, to_format=to_fmt)
        except ValueError as e:
            return error(f"Format de date invalide: {e}", code="parse_error")

    @action("diff")
    async def diff(self, payload: dict) -> dict:
        date1_str = payload.get("date1")
        date2_str = payload.get("date2")
        if not date1_str or not date2_str:
            return error("Les champs 'date1' et 'date2' sont obligatoires", code="missing_field")
        try:
            d1 = datetime.fromisoformat(date1_str)
            d2 = datetime.fromisoformat(date2_str)
            delta = d2 - d1
            return ok(
                days=delta.days,
                hours=int(delta.total_seconds() // 3600),
                minutes=int(delta.total_seconds() // 60),
                seconds=int(delta.total_seconds()),
                date1=date1_str,
                date2=date2_str
            )
        except ValueError as e:
            return error(f"Format de date invalide: {e}", code="parse_error")

    @action("add")
    async def add_duration(self, payload: dict) -> dict:
        date_str = payload.get("date")
        if not date_str:
            return error("Le champ 'date' est obligatoire", code="missing_field")
        try:
            dt = datetime.fromisoformat(date_str)
            days = int(payload.get("days", 0))
            hours = int(payload.get("hours", 0))
            minutes = int(payload.get("minutes", 0))
            result = dt + timedelta(days=days, hours=hours, minutes=minutes)
            return ok(
                input=date_str,
                result=result.isoformat(),
                added={"days": days, "hours": hours, "minutes": minutes}
            )
        except ValueError as e:
            return error(f"Format de date invalide: {e}", code="parse_error")

    @action("is_past")
    async def is_past(self, payload: dict) -> dict:
        date_str = payload.get("date")
        if not date_str:
            return error("Le champ 'date' est obligatoire", code="missing_field")
        try:
            dt = datetime.fromisoformat(date_str)
            if dt.tzinfo is None:
                dt = dt.replace(tzinfo=timezone.utc)
            now = datetime.now(timezone.utc)
            return ok(date=date_str, is_past=dt < now, is_future=dt > now)
        except ValueError as e:
            return error(f"Format de date invalide: {e}", code="parse_error")

