from pydantic import BaseModel
from sqlalchemy import Column, Integer, String
from sqlalchemy.orm import declarative_base
from xcore.sdk import (
    TrustedBase, AutoDispatchMixin, RoutedPlugin,
    BaseAsyncRepository, action, route, validate_payload, ok, error
)

Base = declarative_base()

class Role(Base):
    __tablename__ = "roles"
    id = Column(Integer, primary_key=True)
    name = Column(String, nullable=False, unique=True)
    description = Column(String, nullable=True)

class UserRole(Base):
    __tablename__ = "user_roles"
    id = Column(Integer, primary_key=True)
    user_id = Column(Integer, nullable=False)
    role_id = Column(Integer, nullable=False)

class CreateRole(BaseModel):
    name: str
    description: str | None = None

class AssignRole(BaseModel):
    user_id: int
    role_id: int

class RoleRepository(BaseAsyncRepository[Role]):
    pass

class UserRoleRepository(BaseAsyncRepository[UserRole]):
    pass

class Plugin(RoutedPlugin, AutoDispatchMixin, TrustedBase):

    async def on_load(self) -> None:
        self.db = self.get_service("db")
        self.cache = self.get_service("cache")
        self.role_repo = RoleRepository(Role)
        self.user_role_repo = UserRoleRepository(UserRole)

    @action("create_role")
    @validate_payload(CreateRole, type_response="dict")
    async def create_role_ipc(self, data: dict) -> dict:
        async with self.db.session() as session:
            role = Role(name=data["name"].lower(), description=data.get("description"))
            created = await self.role_repo.create(session, role)
            await self.cache.delete("roles:list")
            return ok(id=created.id, name=created.name)

    @action("assign_role")
    @validate_payload(AssignRole, type_response="dict")
    async def assign_role_ipc(self, data: dict) -> dict:
        async with self.db.session() as session:
            role = await self.role_repo.get_by_id(session, data["role_id"])
            if not role:
                return error("Rôle non trouvé", code="not_found")
            ur = UserRole(user_id=data["user_id"], role_id=data["role_id"])
            await self.user_role_repo.create(session, ur)
            await self.cache.delete(f"user_roles:{data['user_id']}")
            return ok(user_id=data["user_id"], role_id=data["role_id"], role_name=role.name)

    @action("get_user_roles")
    async def get_user_roles_ipc(self, payload: dict) -> dict:
        user_id = payload.get("user_id")
        if not user_id:
            return error("Le champ 'user_id' est obligatoire", code="missing_field")
        cache_key = f"user_roles:{user_id}"
        cached = await self.cache.get(cache_key)
        if cached is not None:
            return ok(user_id=user_id, roles=cached, cached=True)
        async with self.db.session() as session:
            all_ur = await self.user_role_repo.get_all(session)
            user_role_ids = [ur.role_id for ur in all_ur if ur.user_id == user_id]
            roles = await self.role_repo.get_all(session)
            user_roles = [r.name for r in roles if r.id in user_role_ids]
            await self.cache.set(cache_key, user_roles, ttl=300)
            return ok(user_id=user_id, roles=user_roles)

    @action("revoke_role")
    async def revoke_role_ipc(self, payload: dict) -> dict:
        user_id = payload.get("user_id")
        role_id = payload.get("role_id")
        if not user_id or not role_id:
            return error("Les champs 'user_id' et 'role_id' sont obligatoires", code="missing_field")
        async with self.db.session() as session:
            all_ur = await self.user_role_repo.get_all(session)
            match = next((ur for ur in all_ur if ur.user_id == user_id and ur.role_id == role_id), None)
            if not match:
                return error("Assignation non trouvée", code="not_found")
            await self.user_role_repo.delete(session, match.id)
            await self.cache.delete(f"user_roles:{user_id}")
            return ok(revoked=True, user_id=user_id, role_id=role_id)

    @action("has_role")
    async def has_role_ipc(self, payload: dict) -> dict:
        user_id = payload.get("user_id")
        role_name = payload.get("role")
        if not user_id or not role_name:
            return error("Les champs 'user_id' et 'role' sont obligatoires", code="missing_field")
        result = await self.get_user_roles_ipc({"user_id": user_id})
        roles = result.get("roles", [])
        return ok(user_id=user_id, role=role_name, has_role=role_name in roles)

    @route("/", method="GET")
    async def list_roles(self):
        cached = await self.cache.get("roles:list")
        if cached:
            return {"roles": cached, "cached": True}
        async with self.db.session() as session:
            roles = await self.role_repo.get_all(session)
            result = [{"id": r.id, "name": r.name, "description": r.description} for r in roles]
            await self.cache.set("roles:list", result, ttl=600)
            return {"roles": result, "cached": False}

    @route("/{role_id}", method="DELETE", status_code=204)
    async def delete_role(self, role_id: int):
        async with self.db.session() as session:
            deleted = await self.role_repo.delete(session, role_id)
            if not deleted:
                return error("Rôle non trouvé", code="not_found")
            await self.cache.delete("roles:list")
            return None

