from datetime import datetime, timezone
from pydantic import BaseModel, Field
from sqlalchemy import Column, Integer, String, Float, DateTime
from sqlalchemy.orm import declarative_base
from xcore.sdk import (
    TrustedBase, AutoDispatchMixin, RoutedPlugin,
    BaseAsyncRepository, action, route, validate_payload, ok, error
)

Base = declarative_base()

TX_TYPES = ("credit", "debit", "transfer")

class Wallet(Base):
    __tablename__ = "wallets"
    id = Column(Integer, primary_key=True)
    user_id = Column(Integer, nullable=False, unique=True)
    balance = Column(Float, default=0.0)
    currency = Column(String, default="EUR")

class WalletTransaction(Base):
    __tablename__ = "wallet_transactions"
    id = Column(Integer, primary_key=True)
    wallet_id = Column(Integer, nullable=False)
    amount = Column(Float, nullable=False)
    tx_type = Column(String, nullable=False)
    description = Column(String, nullable=True)
    reference = Column(String, nullable=True)
    created_at = Column(DateTime, default=lambda: datetime.now(timezone.utc))

class CreateWallet(BaseModel):
    user_id: int
    currency: str = "EUR"
    initial_balance: float = 0.0

class CreditDebit(BaseModel):
    wallet_id: int
    amount: float = Field(gt=0)
    description: str | None = None
    reference: str | None = None

class Transfer(BaseModel):
    from_wallet_id: int
    to_wallet_id: int
    amount: float = Field(gt=0)
    description: str | None = None

class WalletRepository(BaseAsyncRepository[Wallet]):
    pass

class TxRepository(BaseAsyncRepository[WalletTransaction]):
    pass

class Plugin(RoutedPlugin, AutoDispatchMixin, TrustedBase):

    async def on_load(self) -> None:
        self.db = self.get_service("db")
        self.cache = self.get_service("cache")
        self.wallet_repo = WalletRepository(Wallet)
        self.tx_repo = TxRepository(WalletTransaction)

    @action("create_wallet")
    @validate_payload(CreateWallet, type_response="dict")
    async def create_wallet_ipc(self, data: dict) -> dict:
        async with self.db.session() as session:
            wallet = Wallet(
                user_id=data["user_id"],
                currency=data.get("currency", "EUR"),
                balance=max(0.0, data.get("initial_balance", 0.0))
            )
            created = await self.wallet_repo.create(session, wallet)
            return ok(id=created.id, user_id=created.user_id, balance=created.balance, currency=created.currency)

    @action("get_balance")
    async def get_balance_ipc(self, payload: dict) -> dict:
        wallet_id = payload.get("wallet_id")
        user_id = payload.get("user_id")
        if not wallet_id and not user_id:
            return error("'wallet_id' ou 'user_id' requis", code="missing_field")
        cache_key = f"wallet:balance:{wallet_id or f'user:{user_id}'}"
        cached = await self.cache.get(cache_key)
        if cached is not None:
            return ok(**cached)
        async with self.db.session() as session:
            if wallet_id:
                wallet = await self.wallet_repo.get_by_id(session, wallet_id)
            else:
                wallets = await self.wallet_repo.get_all(session)
                wallet = next((w for w in wallets if w.user_id == user_id), None)
            if not wallet:
                return error("Portefeuille non trouvé", code="not_found")
            result = {"wallet_id": wallet.id, "user_id": wallet.user_id, "balance": wallet.balance, "currency": wallet.currency}
            await self.cache.set(cache_key, result, ttl=30)
            return ok(**result)

    @action("credit")
    @validate_payload(CreditDebit, type_response="dict")
    async def credit_ipc(self, data: dict) -> dict:
        async with self.db.session() as session:
            wallet = await self.wallet_repo.get_by_id(session, data["wallet_id"])
            if not wallet:
                return error("Portefeuille non trouvé", code="not_found")
            wallet.balance = round(wallet.balance + data["amount"], 2)
            tx = WalletTransaction(
                wallet_id=data["wallet_id"],
                amount=data["amount"],
                tx_type="credit",
                description=data.get("description"),
                reference=data.get("reference")
            )
            await self.tx_repo.create(session, tx)
            await self.cache.delete(f"wallet:balance:{data['wallet_id']}")
            await self.cache.delete(f"wallet:balance:user:{wallet.user_id}")
            return ok(wallet_id=data["wallet_id"], new_balance=wallet.balance, credited=data["amount"])

    @action("debit")
    @validate_payload(CreditDebit, type_response="dict")
    async def debit_ipc(self, data: dict) -> dict:
        async with self.db.session() as session:
            wallet = await self.wallet_repo.get_by_id(session, data["wallet_id"])
            if not wallet:
                return error("Portefeuille non trouvé", code="not_found")
            if wallet.balance < data["amount"]:
                return error(
                    f"Solde insuffisant ({wallet.balance} {wallet.currency})",
                    code="insufficient_funds"
                )
            wallet.balance = round(wallet.balance - data["amount"], 2)
            tx = WalletTransaction(
                wallet_id=data["wallet_id"],
                amount=data["amount"],
                tx_type="debit",
                description=data.get("description"),
                reference=data.get("reference")
            )
            await self.tx_repo.create(session, tx)
            await self.cache.delete(f"wallet:balance:{data['wallet_id']}")
            await self.cache.delete(f"wallet:balance:user:{wallet.user_id}")
            return ok(wallet_id=data["wallet_id"], new_balance=wallet.balance, debited=data["amount"])

    @action("transfer")
    @validate_payload(Transfer, type_response="dict")
    async def transfer_ipc(self, data: dict) -> dict:
        if data["from_wallet_id"] == data["to_wallet_id"]:
            return error("Impossible de transférer vers le même portefeuille", code="same_wallet")
        debit_result = await self.debit_ipc({"wallet_id": data["from_wallet_id"], "amount": data["amount"], "description": data.get("description"), "reference": f"transfer_to_{data['to_wallet_id']}"})
        if debit_result.get("status") == "error":
            return debit_result
        credit_result = await self.credit_ipc({"wallet_id": data["to_wallet_id"], "amount": data["amount"], "description": data.get("description"), "reference": f"transfer_from_{data['from_wallet_id']}"})
        if credit_result.get("status") == "error":
            await self.credit_ipc({"wallet_id": data["from_wallet_id"], "amount": data["amount"], "description": "Annulation transfert"})
            return credit_result
        return ok(
            transferred=data["amount"],
            from_wallet_id=data["from_wallet_id"],
            to_wallet_id=data["to_wallet_id"],
            from_balance=debit_result["new_balance"],
            to_balance=credit_result["new_balance"]
        )

    @route("/wallet/{wallet_id}/transactions", method="GET")
    async def get_transactions(self, wallet_id: int):
        async with self.db.session() as session:
            all_txs = await self.tx_repo.get_all(session)
            wallet_txs = sorted(
                [t for t in all_txs if t.wallet_id == wallet_id],
                key=lambda t: t.id,
                reverse=True
            )[:100]
            return {
                "wallet_id": wallet_id,
                "transactions": [
                    {"id": t.id, "amount": t.amount, "type": t.tx_type, "description": t.description, "reference": t.reference}
                    for t in wallet_txs
                ]
            }

