import csv
import io
import json
from xcore.sdk import TrustedBase, AutoDispatchMixin, RoutedPlugin, action, route, ok, error

class Plugin(RoutedPlugin, AutoDispatchMixin, TrustedBase):

    async def on_load(self) -> None:
        self.db = self.get_service("db")

    @action("export_table")
    async def export_table_ipc(self, payload: dict) -> dict:
        table = payload.get("table")
        fmt = payload.get("format", "json")
        limit = min(int(payload.get("limit", 1000)), 10000)
        if not table:
            return error("Le champ 'table' est obligatoire", code="missing_field")
        allowed_tables = payload.get("allowed_tables", [])
        if allowed_tables and table not in allowed_tables:
            return error(f"Table '{table}' non autorisée", code="forbidden")
        if fmt not in ("json", "csv"):
            return error("Format invalide. Valeurs: json, csv", code="invalid_param")
        try:
            async with self.db.session() as session:
                result = await session.execute(f"SELECT * FROM {table} LIMIT {limit}")
                rows = result.fetchall()
                columns = list(result.keys())
        except Exception as e:
            return error(f"Erreur de lecture: {e}", code="db_error")
        if fmt == "json":
            data = [dict(zip(columns, row)) for row in rows]
            return ok(table=table, format="json", count=len(data), data=data)
        buf = io.StringIO()
        writer = csv.writer(buf)
        writer.writerow(columns)
        writer.writerows(rows)
        return ok(table=table, format="csv", count=len(rows), csv=buf.getvalue())

    @action("export_query")
    async def export_query_ipc(self, payload: dict) -> dict:
        query = payload.get("query", "")
        fmt = payload.get("format", "json")
        if not query:
            return error("Le champ 'query' est obligatoire", code="missing_field")
        forbidden_keywords = ("drop ", "delete ", "insert ", "update ", "truncate ", "alter ", "create ")
        query_lower = query.lower().strip()
        if any(kw in query_lower for kw in forbidden_keywords):
            return error("Seules les requêtes SELECT sont autorisées", code="forbidden")
        if not query_lower.startswith("select "):
            return error("La requête doit commencer par SELECT", code="invalid_query")
        try:
            async with self.db.session() as session:
                result = await session.execute(query)
                rows = result.fetchall()
                columns = list(result.keys())
        except Exception as e:
            return error(f"Erreur SQL: {e}", code="db_error")
        if fmt == "csv":
            buf = io.StringIO()
            writer = csv.writer(buf)
            writer.writerow(columns)
            writer.writerows(rows)
            return ok(format="csv", count=len(rows), csv=buf.getvalue())
        data = [dict(zip(columns, row)) for row in rows]
        return ok(format="json", count=len(data), data=data)

    @route("/tables", method="GET")
    async def list_exportable_tables(self):
        try:
            async with self.db.session() as session:
                result = await session.execute("SELECT name FROM sqlite_master WHERE type='table'")
                tables = [row[0] for row in result.fetchall()]
            return {"tables": tables}
        except Exception:
            try:
                async with self.db.session() as session:
                    result = await session.execute("SELECT table_name FROM information_schema.tables WHERE table_schema = 'public'")
                    tables = [row[0] for row in result.fetchall()]
                return {"tables": tables}
            except Exception as e:
                return {"tables": [], "error": str(e)}

