import hashlib
from pydantic import BaseModel, Field
from sqlalchemy import Column, Integer, String, Boolean, Float
from sqlalchemy.orm import declarative_base
from xcore.sdk import (
    TrustedBase, AutoDispatchMixin, RoutedPlugin,
    BaseAsyncRepository, action, route, validate_payload, ok, error
)

Base = declarative_base()

class FeatureFlag(Base):
    __tablename__ = "feature_flags"
    id = Column(Integer, primary_key=True)
    name = Column(String, nullable=False, unique=True)
    enabled = Column(Boolean, default=False)
    rollout_percent = Column(Float, default=100.0)
    environment = Column(String, default="production")
    description = Column(String, nullable=True)

class CreateFlag(BaseModel):
    name: str
    enabled: bool = False
    rollout_percent: float = Field(default=100.0, ge=0.0, le=100.0)
    environment: str = "production"
    description: str | None = None

class FlagRepository(BaseAsyncRepository[FeatureFlag]):
    pass

def _is_in_rollout(flag_name: str, user_id: int | str, percent: float) -> bool:
    if percent >= 100.0:
        return True
    if percent <= 0.0:
        return False
    key = f"{flag_name}:{user_id}"
    bucket = int(hashlib.md5(key.encode()).hexdigest(), 16) % 100
    return bucket < percent

class Plugin(RoutedPlugin, AutoDispatchMixin, TrustedBase):

    async def on_load(self) -> None:
        self.db = self.get_service("db")
        self.cache = self.get_service("cache")
        self.repo = FlagRepository(FeatureFlag)

    @action("create_flag")
    @validate_payload(CreateFlag, type_response="dict")
    async def create_flag_ipc(self, data: dict) -> dict:
        async with self.db.session() as session:
            flag = FeatureFlag(
                name=data["name"].lower().replace(" ", "_"),
                enabled=data.get("enabled", False),
                rollout_percent=data.get("rollout_percent", 100.0),
                environment=data.get("environment", "production"),
                description=data.get("description")
            )
            created = await self.repo.create(session, flag)
            await self.cache.delete("flags:all")
            return ok(id=created.id, name=created.name, enabled=created.enabled)

    @action("is_enabled")
    async def is_enabled_ipc(self, payload: dict) -> dict:
        flag_name = payload.get("flag")
        user_id = payload.get("user_id")
        env = payload.get("environment", "production")
        if not flag_name:
            return error("Le champ 'flag' est obligatoire", code="missing_field")
        cache_key = f"flag:{env}:{flag_name}"
        cached = await self.cache.get(cache_key)
        if cached is not None:
            flag_data = cached
        else:
            async with self.db.session() as session:
                flags = await self.repo.get_all(session)
                flag = next((f for f in flags if f.name == flag_name and f.environment == env), None)
            if not flag:
                return ok(flag=flag_name, enabled=False, reason="flag_not_found")
            flag_data = {"enabled": flag.enabled, "rollout_percent": flag.rollout_percent}
            await self.cache.set(cache_key, flag_data, ttl=60)
        if not flag_data["enabled"]:
            return ok(flag=flag_name, enabled=False, reason="flag_disabled")
        if user_id is not None:
            in_rollout = _is_in_rollout(flag_name, user_id, flag_data["rollout_percent"])
            return ok(flag=flag_name, enabled=in_rollout, rollout_percent=flag_data["rollout_percent"], user_id=user_id)
        return ok(flag=flag_name, enabled=True, rollout_percent=flag_data["rollout_percent"])

    @action("toggle_flag")
    async def toggle_flag_ipc(self, payload: dict) -> dict:
        flag_name = payload.get("flag")
        enabled = payload.get("enabled")
        if not flag_name or enabled is None:
            return error("Les champs 'flag' et 'enabled' sont obligatoires", code="missing_field")
        async with self.db.session() as session:
            flags = await self.repo.get_all(session)
            flag = next((f for f in flags if f.name == flag_name), None)
            if not flag:
                return error("Flag non trouvé", code="not_found")
            flag.enabled = bool(enabled)
            await self.cache.delete(f"flag:{flag.environment}:{flag_name}")
            await self.cache.delete("flags:all")
            return ok(flag=flag_name, enabled=flag.enabled)

    @route("/", method="GET")
    async def list_flags(self):
        cached = await self.cache.get("flags:all")
        if cached:
            return {"flags": cached, "cached": True}
        async with self.db.session() as session:
            flags = await self.repo.get_all(session)
            result = [{
                "id": f.id,
                "name": f.name,
                "enabled": f.enabled,
                "rollout_percent": f.rollout_percent,
                "environment": f.environment,
                "description": f.description
            } for f in flags]
            await self.cache.set("flags:all", result, ttl=120)
            return {"flags": result, "cached": False}

    @route("/{flag_id}", method="DELETE", status_code=204)
    async def delete_flag(self, flag_id: int):
        async with self.db.session() as session:
            flag = await self.repo.get_by_id(session, flag_id)
            if not flag:
                return error("Flag non trouvé", code="not_found")
            await self.repo.delete(session, flag_id)
            await self.cache.delete(f"flag:{flag.environment}:{flag.name}")
            await self.cache.delete("flags:all")
            return None

