import hashlib
import hmac
import re
import secrets
from xcore.sdk import TrustedBase, AutoDispatchMixin, action, ok, error

MIN_LENGTH = 8
SPECIAL_CHARS = set("!@#$%^&*()_+-=[]{}|;:,.<>?")

def _derive_key(password: str, salt: str, iterations: int = 260000) -> str:
    return hashlib.pbkdf2_hmac(
        "sha256",
        password.encode("utf-8"),
        salt.encode("utf-8"),
        iterations
    ).hex()

class Plugin(AutoDispatchMixin, TrustedBase):

    @action("hash")
    async def hash_password(self, payload: dict) -> dict:
        password = payload.get("password", "")
        if not password:
            return error("Le champ 'password' est obligatoire", code="missing_field")
        if len(password) < MIN_LENGTH:
            return error(f"Mot de passe trop court (min {MIN_LENGTH} caractères)", code="too_short")
        iterations = int(payload.get("iterations", 260000))
        salt = secrets.token_hex(32)
        hashed = _derive_key(password, salt, iterations)
        stored = f"pbkdf2:sha256:{iterations}:{salt}:{hashed}"
        return ok(hash=stored, algorithm="pbkdf2-sha256", iterations=iterations)

    @action("verify")
    async def verify_password(self, payload: dict) -> dict:
        password = payload.get("password", "")
        stored_hash = payload.get("hash", "")
        if not password or not stored_hash:
            return error("Les champs 'password' et 'hash' sont obligatoires", code="missing_field")
        try:
            parts = stored_hash.split(":")
            if len(parts) != 5 or parts[0] != "pbkdf2":
                return error("Format de hash invalide", code="invalid_hash")
            _, algo, iterations_str, salt, expected = parts
            iterations = int(iterations_str)
            computed = _derive_key(password, salt, iterations)
            valid = hmac.compare_digest(computed, expected)
            return ok(valid=valid)
        except Exception as e:
            return error(f"Erreur de vérification: {e}", code="verification_error")

    @action("check_strength")
    async def check_strength(self, payload: dict) -> dict:
        password = payload.get("password", "")
        if not password:
            return error("Le champ 'password' est obligatoire", code="missing_field")
        issues = []
        score = 0
        if len(password) >= 8: score += 1
        else: issues.append("Trop court (min 8 caractères)")
        if len(password) >= 12: score += 1
        if len(password) >= 16: score += 1
        if re.search(r"[a-z]", password): score += 1
        else: issues.append("Manque de minuscules")
        if re.search(r"[A-Z]", password): score += 1
        else: issues.append("Manque de majuscules")
        if re.search(r"\d", password): score += 1
        else: issues.append("Manque de chiffres")
        if any(c in SPECIAL_CHARS for c in password): score += 1
        else: issues.append("Manque de caractères spéciaux")
        common_patterns = [r"123", r"abc", r"qwerty", r"password", r"admin"]
        if any(re.search(p, password, re.IGNORECASE) for p in common_patterns):
            score -= 2
            issues.append("Contient un motif courant")
        score = max(0, score)
        strength_map = {0: "very_weak", 1: "weak", 2: "weak", 3: "fair", 4: "good", 5: "strong", 6: "very_strong", 7: "excellent"}
        strength = strength_map.get(score, "excellent" if score >= 7 else "very_weak")
        return ok(
            score=score,
            max_score=7,
            strength=strength,
            issues=issues,
            acceptable=score >= 3
        )

    @action("generate")
    async def generate_password(self, payload: dict) -> dict:
        length = max(12, min(int(payload.get("length", 16)), 128))
        include_symbols = payload.get("include_symbols", True)
        alphabet = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789"
        if include_symbols:
            alphabet += "!@#$%^&*"
        password = "".join(secrets.choice(alphabet) for _ in range(length))
        check_result = await self.check_strength({"password": password})
        return ok(
            password=password,
            length=length,
            strength=check_result.get("strength"),
            score=check_result.get("score")
        )

