import json
import time
import uuid
from pydantic import BaseModel
from xcore.sdk import TrustedBase, AutoDispatchMixin, RoutedPlugin, action, route, validate_payload, ok, error

QUEUE_TTL = 86400

class EnqueueTask(BaseModel):
    queue: str
    payload: dict
    priority: int = 0
    ttl: int = QUEUE_TTL

class Plugin(RoutedPlugin, AutoDispatchMixin, TrustedBase):

    async def on_load(self) -> None:
        self.cache = self.get_service("cache")

    def _queue_key(self, queue_name: str) -> str:
        return f"queue:{queue_name}"

    async def _get_queue(self, queue_name: str) -> list[dict]:
        raw = await self.cache.get(self._queue_key(queue_name))
        if raw is None:
            return []
        if isinstance(raw, list):
            return raw
        try:
            return json.loads(raw)
        except Exception:
            return []

    async def _save_queue(self, queue_name: str, items: list[dict]) -> None:
        await self.cache.set(self._queue_key(queue_name), items, ttl=QUEUE_TTL)

    @action("enqueue")
    @validate_payload(EnqueueTask, type_response="dict")
    async def enqueue_ipc(self, data: dict) -> dict:
        queue_name = data["queue"]
        task = {
            "id": str(uuid.uuid4()),
            "payload": data["payload"],
            "priority": data.get("priority", 0),
            "enqueued_at": time.time(),
            "attempts": 0
        }
        items = await self._get_queue(queue_name)
        items.append(task)
        items.sort(key=lambda t: -t.get("priority", 0))
        await self._save_queue(queue_name, items)
        return ok(task_id=task["id"], queue=queue_name, position=len(items), priority=task["priority"])

    @action("dequeue")
    async def dequeue_ipc(self, payload: dict) -> dict:
        queue_name = payload.get("queue")
        if not queue_name:
            return error("Le champ 'queue' est obligatoire", code="missing_field")
        items = await self._get_queue(queue_name)
        if not items:
            return ok(task=None, queue=queue_name, empty=True)
        task = items.pop(0)
        task["attempts"] = task.get("attempts", 0) + 1
        task["dequeued_at"] = time.time()
        await self._save_queue(queue_name, items)
        return ok(task=task, queue=queue_name, remaining=len(items))

    @action("peek")
    async def peek_ipc(self, payload: dict) -> dict:
        queue_name = payload.get("queue")
        count = min(int(payload.get("count", 1)), 50)
        if not queue_name:
            return error("Le champ 'queue' est obligatoire", code="missing_field")
        items = await self._get_queue(queue_name)
        return ok(tasks=items[:count], queue=queue_name, total=len(items))

    @action("purge")
    async def purge_ipc(self, payload: dict) -> dict:
        queue_name = payload.get("queue")
        if not queue_name:
            return error("Le champ 'queue' est obligatoire", code="missing_field")
        items = await self._get_queue(queue_name)
        count = len(items)
        await self.cache.delete(self._queue_key(queue_name))
        return ok(queue=queue_name, purged=count)

    @action("stats")
    async def stats_ipc(self, payload: dict) -> dict:
        queue_name = payload.get("queue")
        if not queue_name:
            return error("Le champ 'queue' est obligatoire", code="missing_field")
        items = await self._get_queue(queue_name)
        if not items:
            return ok(queue=queue_name, size=0, oldest_age=None, avg_priority=0)
        now = time.time()
        ages = [now - t.get("enqueued_at", now) for t in items]
        priorities = [t.get("priority", 0) for t in items]
        return ok(
            queue=queue_name,
            size=len(items),
            oldest_age_seconds=round(max(ages), 1),
            avg_priority=round(sum(priorities) / len(priorities), 2)
        )

    @route("/{queue_name}/size", method="GET")
    async def queue_size(self, queue_name: str):
        items = await self._get_queue(queue_name)
        return {"queue": queue_name, "size": len(items)}

