import re
from xcore.sdk import TrustedBase, AutoDispatchMixin, RoutedPlugin, action, route, ok, error

IPV4_RE = re.compile(
    r"^(25[0-5]|2[0-4]\d|[01]?\d\d?)\.(25[0-5]|2[0-4]\d|[01]?\d\d?)\."
    r"(25[0-5]|2[0-4]\d|[01]?\d\d?)\.(25[0-5]|2[0-4]\d|[01]?\d\d?)$"
)
PRIVATE_RANGES = [
    ("10.0.0.0", "10.255.255.255"),
    ("172.16.0.0", "172.31.255.255"),
    ("192.168.0.0", "192.168.255.255"),
    ("127.0.0.0", "127.255.255.255"),
    ("169.254.0.0", "169.254.255.255"),
]

def _ip_to_int(ip: str) -> int:
    parts = [int(p) for p in ip.split(".")]
    return (parts[0] << 24) | (parts[1] << 16) | (parts[2] << 8) | parts[3]

def _is_private(ip: str) -> bool:
    ip_int = _ip_to_int(ip)
    for start, end in PRIVATE_RANGES:
        if _ip_to_int(start) <= ip_int <= _ip_to_int(end):
            return True
    return False

def _is_in_cidr(ip: str, cidr: str) -> bool:
    try:
        network, prefix = cidr.split("/")
        prefix_len = int(prefix)
        mask = (0xFFFFFFFF << (32 - prefix_len)) & 0xFFFFFFFF
        return (_ip_to_int(ip) & mask) == (_ip_to_int(network) & mask)
    except Exception:
        return ip == cidr

class Plugin(RoutedPlugin, AutoDispatchMixin, TrustedBase):

    async def on_load(self) -> None:
        self.cache = self.get_service("cache")

    @action("analyze")
    async def analyze_ipc(self, payload: dict) -> dict:
        ip = payload.get("ip", "").strip()
        if not ip:
            return error("Le champ 'ip' est obligatoire", code="missing_field")
        is_valid_ipv4 = bool(IPV4_RE.match(ip))
        if not is_valid_ipv4:
            is_ipv6 = ":" in ip
            return ok(
                ip=ip,
                valid=is_ipv6,
                version="ipv6" if is_ipv6 else "invalid",
                is_private=False,
                is_loopback=ip == "::1"
            )
        is_private = _is_private(ip)
        parts = ip.split(".")
        return ok(
            ip=ip,
            valid=True,
            version="ipv4",
            octets=[int(p) for p in parts],
            is_private=is_private,
            is_public=not is_private,
            is_loopback=ip.startswith("127."),
            class_=(
                "A" if int(parts[0]) < 128 else
                "B" if int(parts[0]) < 192 else
                "C" if int(parts[0]) < 224 else
                "D" if int(parts[0]) < 240 else "E"
            )
        )

    @action("check_blacklist")
    async def check_blacklist_ipc(self, payload: dict) -> dict:
        ip = payload.get("ip", "").strip()
        if not ip:
            return error("Le champ 'ip' est obligatoire", code="missing_field")
        blacklist = await self.cache.get("ip:blacklist") or []
        is_blocked = any(_is_in_cidr(ip, entry) for entry in blacklist)
        return ok(ip=ip, blocked=is_blocked, blacklist_size=len(blacklist))

    @action("add_to_blacklist")
    async def add_to_blacklist_ipc(self, payload: dict) -> dict:
        entry = payload.get("ip", "").strip()
        if not entry:
            return error("Le champ 'ip' est obligatoire", code="missing_field")
        blacklist = await self.cache.get("ip:blacklist") or []
        if entry not in blacklist:
            blacklist.append(entry)
            await self.cache.set("ip:blacklist", blacklist, ttl=86400 * 30)
        return ok(added=entry, blacklist_size=len(blacklist))

    @action("remove_from_blacklist")
    async def remove_from_blacklist_ipc(self, payload: dict) -> dict:
        entry = payload.get("ip", "").strip()
        if not entry:
            return error("Le champ 'ip' est obligatoire", code="missing_field")
        blacklist = await self.cache.get("ip:blacklist") or []
        if entry in blacklist:
            blacklist.remove(entry)
            await self.cache.set("ip:blacklist", blacklist, ttl=86400 * 30)
            return ok(removed=entry, blacklist_size=len(blacklist))
        return error(f"'{entry}' n'est pas dans la blacklist", code="not_found")

    @route("/blacklist", method="GET")
    async def get_blacklist(self):
        blacklist = await self.cache.get("ip:blacklist") or []
        return {"blacklist": blacklist, "count": len(blacklist)}

