import re
from pydantic import BaseModel
from sqlalchemy import Column, Integer, String, Text
from sqlalchemy.orm import declarative_base
from xcore.sdk import (
    TrustedBase, AutoDispatchMixin, RoutedPlugin,
    BaseAsyncRepository, action, route, validate_payload, ok, error
)

Base = declarative_base()

STOP_WORDS = {"le", "la", "les", "de", "du", "des", "un", "une", "et", "ou", "the", "a", "an", "is", "in", "on", "at"}

class SearchIndex(Base):
    __tablename__ = "search_index"
    id = Column(Integer, primary_key=True)
    entity_type = Column(String, nullable=False)
    entity_id = Column(Integer, nullable=False)
    title = Column(String, nullable=False)
    content = Column(Text, nullable=True)
    keywords = Column(Text, nullable=True)

class IndexDocument(BaseModel):
    entity_type: str
    entity_id: int
    title: str
    content: str | None = None
    keywords: list[str] = []

class IndexRepository(BaseAsyncRepository[SearchIndex]):
    pass

def _tokenize(text: str) -> set[str]:
    words = re.findall(r"\w+", text.lower())
    return {w for w in words if len(w) > 2 and w not in STOP_WORDS}

def _score(doc: SearchIndex, query_tokens: set[str]) -> float:
    score = 0.0
    title_tokens = _tokenize(doc.title)
    content_tokens = _tokenize(doc.content or "")
    kw_tokens = _tokenize(doc.keywords or "")
    for token in query_tokens:
        if token in title_tokens:
            score += 3.0
        if token in kw_tokens:
            score += 2.0
        for t in title_tokens | content_tokens:
            if token in t:
                score += 0.5
    return score

class Plugin(RoutedPlugin, AutoDispatchMixin, TrustedBase):

    async def on_load(self) -> None:
        self.db = self.get_service("db")
        self.cache = self.get_service("cache")
        self.repo = IndexRepository(SearchIndex)

    @action("index")
    @validate_payload(IndexDocument, type_response="dict")
    async def index_document_ipc(self, data: dict) -> dict:
        async with self.db.session() as session:
            all_docs = await self.repo.get_all(session)
            existing = next(
                (d for d in all_docs if d.entity_type == data["entity_type"] and d.entity_id == data["entity_id"]),
                None
            )
            kw_str = " ".join(data.get("keywords", []))
            if existing:
                existing.title = data["title"]
                existing.content = data.get("content")
                existing.keywords = kw_str
                doc = existing
            else:
                doc = SearchIndex(
                    entity_type=data["entity_type"],
                    entity_id=data["entity_id"],
                    title=data["title"],
                    content=data.get("content"),
                    keywords=kw_str
                )
                await self.repo.create(session, doc)
            await self.cache.delete("search:index_size")
            return ok(
                indexed=True,
                entity_type=data["entity_type"],
                entity_id=data["entity_id"]
            )

    @action("search")
    async def search_ipc(self, payload: dict) -> dict:
        query = payload.get("query", "").strip()
        entity_type = payload.get("entity_type")
        limit = min(int(payload.get("limit", 10)), 50)
        if not query:
            return error("Le champ 'query' est obligatoire", code="missing_field")
        if len(query) < 2:
            return error("La requête doit contenir au moins 2 caractères", code="query_too_short")
        query_tokens = _tokenize(query)
        async with self.db.session() as session:
            all_docs = await self.repo.get_all(session)
        if entity_type:
            all_docs = [d for d in all_docs if d.entity_type == entity_type]
        scored = []
        for doc in all_docs:
            score = _score(doc, query_tokens)
            if score > 0:
                scored.append({
                    "entity_type": doc.entity_type,
                    "entity_id": doc.entity_id,
                    "title": doc.title,
                    "score": round(score, 2)
                })
        scored.sort(key=lambda x: x["score"], reverse=True)
        return ok(
            query=query,
            results=scored[:limit],
            total=len(scored),
            limit=limit
        )

    @action("remove")
    async def remove_document_ipc(self, payload: dict) -> dict:
        entity_type = payload.get("entity_type")
        entity_id = payload.get("entity_id")
        if not entity_type or entity_id is None:
            return error("Les champs 'entity_type' et 'entity_id' sont obligatoires", code="missing_field")
        async with self.db.session() as session:
            all_docs = await self.repo.get_all(session)
            match = next((d for d in all_docs if d.entity_type == entity_type and d.entity_id == entity_id), None)
            if not match:
                return error("Document non trouvé dans l'index", code="not_found")
            await self.repo.delete(session, match.id)
            await self.cache.delete("search:index_size")
            return ok(removed=True, entity_type=entity_type, entity_id=entity_id)

    @route("/stats", method="GET")
    async def index_stats(self):
        async with self.db.session() as session:
            all_docs = await self.repo.get_all(session)
        by_type: dict[str, int] = {}
        for doc in all_docs:
            by_type[doc.entity_type] = by_type.get(doc.entity_type, 0) + 1
        return {"total_documents": len(all_docs), "by_type": by_type}

