import json
from pydantic import BaseModel
from sqlalchemy import Column, Integer, String, Text
from sqlalchemy.orm import declarative_base
from xcore.sdk import (
    TrustedBase, AutoDispatchMixin, RoutedPlugin,
    BaseAsyncRepository, action, route, validate_payload, ok, error
)

Base = declarative_base()

class ConfigEntry(Base):
    __tablename__ = "config_entries"
    id = Column(Integer, primary_key=True)
    namespace = Column(String, nullable=False, default="default")
    key = Column(String, nullable=False)
    value = Column(Text, nullable=True)
    value_type = Column(String, default="string")
    description = Column(String, nullable=True)

class SetConfig(BaseModel):
    namespace: str = "default"
    key: str
    value: str
    value_type: str = "string"
    description: str | None = None

class ConfigRepository(BaseAsyncRepository[ConfigEntry]):
    pass

VALUE_TYPES = {"string", "int", "float", "bool", "json"}

def _coerce(value: str, value_type: str):
    if value_type == "int":
        return int(value)
    if value_type == "float":
        return float(value)
    if value_type == "bool":
        return value.lower() in ("true", "1", "yes")
    if value_type == "json":
        return json.loads(value)
    return value

class Plugin(RoutedPlugin, AutoDispatchMixin, TrustedBase):

    async def on_load(self) -> None:
        self.db = self.get_service("db")
        self.cache = self.get_service("cache")
        self.repo = ConfigRepository(ConfigEntry)

    @action("set")
    @validate_payload(SetConfig, type_response="dict")
    async def set_ipc(self, data: dict) -> dict:
        ns = data.get("namespace", "default")
        key = data["key"]
        value_type = data.get("value_type", "string")
        if value_type not in VALUE_TYPES:
            return error(f"Type invalide. Valeurs: {VALUE_TYPES}", code="invalid_type")
        try:
            _coerce(data["value"], value_type)
        except (ValueError, TypeError) as e:
            return error(f"Valeur incompatible avec le type '{value_type}': {e}", code="type_mismatch")
        async with self.db.session() as session:
            all_entries = await self.repo.get_all(session)
            existing = next((e for e in all_entries if e.namespace == ns and e.key == key), None)
            if existing:
                existing.value = data["value"]
                existing.value_type = value_type
                if data.get("description"):
                    existing.description = data["description"]
            else:
                entry = ConfigEntry(
                    namespace=ns,
                    key=key,
                    value=data["value"],
                    value_type=value_type,
                    description=data.get("description")
                )
                await self.repo.create(session, entry)
            await self.cache.delete(f"config:{ns}:{key}")
            await self.cache.delete(f"config:ns:{ns}")
            return ok(namespace=ns, key=key, value=data["value"], value_type=value_type)

    @action("get")
    async def get_ipc(self, payload: dict) -> dict:
        key = payload.get("key")
        namespace = payload.get("namespace", "default")
        default = payload.get("default")
        inherit = payload.get("inherit", True)
        if not key:
            return error("Le champ 'key' est obligatoire", code="missing_field")
        ns_parts = namespace.split(".")
        namespaces_to_try = []
        if inherit:
            for i in range(len(ns_parts), 0, -1):
                namespaces_to_try.append(".".join(ns_parts[:i]))
            namespaces_to_try.append("default")
        else:
            namespaces_to_try = [namespace]
        async with self.db.session() as session:
            all_entries = await self.repo.get_all(session)
        for ns in namespaces_to_try:
            entry = next((e for e in all_entries if e.namespace == ns and e.key == key), None)
            if entry:
                try:
                    coerced = _coerce(entry.value, entry.value_type)
                except Exception:
                    coerced = entry.value
                return ok(
                    namespace=ns,
                    key=key,
                    value=coerced,
                    raw_value=entry.value,
                    value_type=entry.value_type,
                    resolved_from=ns
                )
        if default is not None:
            return ok(namespace=namespace, key=key, value=default, default=True)
        return error(f"Clé '{key}' non trouvée dans '{namespace}'", code="not_found")

    @action("get_namespace")
    async def get_namespace_ipc(self, payload: dict) -> dict:
        namespace = payload.get("namespace", "default")
        cache_key = f"config:ns:{namespace}"
        cached = await self.cache.get(cache_key)
        if cached is not None:
            return ok(namespace=namespace, config=cached, cached=True)
        async with self.db.session() as session:
            all_entries = await self.repo.get_all(session)
        ns_entries = [e for e in all_entries if e.namespace == namespace]
        config = {}
        for e in ns_entries:
            try:
                config[e.key] = _coerce(e.value, e.value_type)
            except Exception:
                config[e.key] = e.value
        await self.cache.set(cache_key, config, ttl=300)
        return ok(namespace=namespace, config=config, count=len(config))

    @action("delete")
    async def delete_ipc(self, payload: dict) -> dict:
        key = payload.get("key")
        namespace = payload.get("namespace", "default")
        if not key:
            return error("Le champ 'key' est obligatoire", code="missing_field")
        async with self.db.session() as session:
            all_entries = await self.repo.get_all(session)
            entry = next((e for e in all_entries if e.namespace == namespace and e.key == key), None)
            if not entry:
                return error(f"Clé '{key}' non trouvée dans '{namespace}'", code="not_found")
            await self.repo.delete(session, entry.id)
            await self.cache.delete(f"config:{namespace}:{key}")
            await self.cache.delete(f"config:ns:{namespace}")
            return ok(deleted=True, namespace=namespace, key=key)

    @route("/namespaces", method="GET")
    async def list_namespaces(self):
        async with self.db.session() as session:
            all_entries = await self.repo.get_all(session)
        namespaces = sorted(set(e.namespace for e in all_entries))
        return {"namespaces": namespaces, "count": len(namespaces)}

    @route("/{namespace}", method="GET")
    async def get_namespace_http(self, namespace: str):
        result = await self.get_namespace_ipc({"namespace": namespace})
        if result.get("status") == "error":
            return result
        return {"namespace": namespace, "config": result.get("config", {})}

