import base64
import hashlib
import hmac
import os
from pydantic import BaseModel
from sqlalchemy import Column, Integer, String, Text
from sqlalchemy.orm import declarative_base
from xcore.sdk import (
    TrustedBase, AutoDispatchMixin, RoutedPlugin,
    BaseAsyncRepository, action, route, validate_payload, ok, error
)

Base = declarative_base()

class VaultSecret(Base):
    __tablename__ = "vault_secrets"
    id = Column(Integer, primary_key=True)
    name = Column(String, nullable=False, unique=True)
    encrypted_value = Column(Text, nullable=False)
    owner_id = Column(Integer, nullable=True)
    description = Column(String, nullable=True)

class StoreSecret(BaseModel):
    name: str
    value: str
    owner_id: int | None = None
    description: str | None = None

class VaultRepository(BaseAsyncRepository[VaultSecret]):
    pass

def _derive_key(master_key: str, name: str) -> bytes:
    return hashlib.pbkdf2_hmac("sha256", master_key.encode(), name.encode(), 100000, dklen=32)

def _encrypt(value: str, key: bytes) -> str:
    iv = os.urandom(16)
    xor_key = key[:len(iv)]
    encrypted = bytes(b ^ k for b, k in zip(value.encode(), (xor_key * (len(value) // len(xor_key) + 1))[:len(value)]))
    payload = iv + encrypted
    mac = hmac.new(key, payload, hashlib.sha256).digest()
    return base64.b64encode(mac + payload).decode()

def _decrypt(encrypted_b64: str, key: bytes) -> str:
    raw = base64.b64decode(encrypted_b64.encode())
    mac, payload = raw[:32], raw[32:]
    expected_mac = hmac.new(key, payload, hashlib.sha256).digest()
    if not hmac.compare_digest(mac, expected_mac):
        raise ValueError("Signature invalide - données corrompues")
    iv, encrypted = payload[:16], payload[16:]
    xor_key = key[:len(iv)]
    decrypted = bytes(b ^ k for b, k in zip(encrypted, (xor_key * (len(encrypted) // len(xor_key) + 1))[:len(encrypted)]))
    return decrypted.decode()

class Plugin(RoutedPlugin, AutoDispatchMixin, TrustedBase):

    async def on_load(self) -> None:
        self.db = self.get_service("db")
        self.cache = self.get_service("cache")
        self.repo = VaultRepository(VaultSecret)
        self._master_key = self.ctx.env.get("VAULT_MASTER_KEY", "default-dev-key-change-in-prod")

    @action("store")
    @validate_payload(StoreSecret, type_response="dict")
    async def store_ipc(self, data: dict) -> dict:
        name = data["name"]
        value = data["value"]
        if not value:
            return error("Le secret ne peut pas être vide", code="empty_secret")
        key = _derive_key(self._master_key, name)
        encrypted = _encrypt(value, key)
        async with self.db.session() as session:
            all_secrets = await self.repo.get_all(session)
            existing = next((s for s in all_secrets if s.name == name), None)
            if existing:
                existing.encrypted_value = encrypted
                existing.description = data.get("description", existing.description)
            else:
                secret = VaultSecret(
                    name=name,
                    encrypted_value=encrypted,
                    owner_id=data.get("owner_id"),
                    description=data.get("description")
                )
                await self.repo.create(session, secret)
            await self.cache.delete(f"vault:meta:{name}")
            return ok(stored=True, name=name, description=data.get("description"))

    @action("retrieve")
    async def retrieve_ipc(self, payload: dict) -> dict:
        name = payload.get("name")
        if not name:
            return error("Le champ 'name' est obligatoire", code="missing_field")
        async with self.db.session() as session:
            all_secrets = await self.repo.get_all(session)
            secret = next((s for s in all_secrets if s.name == name), None)
        if not secret:
            return error(f"Secret '{name}' non trouvé", code="not_found")
        try:
            key = _derive_key(self._master_key, name)
            value = _decrypt(secret.encrypted_value, key)
            return ok(name=name, value=value, owner_id=secret.owner_id)
        except ValueError as e:
            return error(f"Erreur de déchiffrement: {e}", code="decrypt_error")

    @action("delete")
    async def delete_ipc(self, payload: dict) -> dict:
        name = payload.get("name")
        if not name:
            return error("Le champ 'name' est obligatoire", code="missing_field")
        async with self.db.session() as session:
            all_secrets = await self.repo.get_all(session)
            secret = next((s for s in all_secrets if s.name == name), None)
            if not secret:
                return error(f"Secret '{name}' non trouvé", code="not_found")
            await self.repo.delete(session, secret.id)
            await self.cache.delete(f"vault:meta:{name}")
            return ok(deleted=True, name=name)

    @action("list_names")
    async def list_names_ipc(self, payload: dict) -> dict:
        owner_id = payload.get("owner_id")
        async with self.db.session() as session:
            all_secrets = await self.repo.get_all(session)
        if owner_id is not None:
            secrets = [s for s in all_secrets if s.owner_id == owner_id]
        else:
            secrets = all_secrets
        names = [{"name": s.name, "description": s.description, "owner_id": s.owner_id} for s in secrets]
        return ok(secrets=names, count=len(names))

    @route("/list", method="GET")
    async def list_secrets_http(self):
        result = await self.list_names_ipc({})
        return {"secrets": result.get("secrets", []), "count": result.get("count", 0)}
